MULTICAN_CONFIG_STATUS_t MULTICAN_CONFIG_0_lInit()
{
  MULTICAN_CONFIG_STATUS_t status;
  uint32_t temp_mo;

  status  = (MULTICAN_CONFIG_STATUS_t)GLOBAL_CAN_Init(MULTICAN_CONFIG_0.global_ptr);

  if (status == MULTICAN_CONFIG_STATUS_SUCCESS)
  {
    /**** NODE0 CONFIGURATION  ****
	---------------------------------------------------------------------------------------------------------------------*/
   
	/* Initialize the GUI configured values for baud rate to NBTR Reg */
	XMC_CAN_NODE_NominalBitTimeConfigure(MULTICAN_CONFIG_0.node0->node_ptr, MULTICAN_CONFIG_0.node0->baudrate_config);

	/* set CCE and INIT bit NCR for node configuration */
	XMC_CAN_NODE_EnableConfigurationChange(MULTICAN_CONFIG_0.node0->node_ptr);

	XMC_CAN_NODE_SetInitBit(MULTICAN_CONFIG_0.node0->node_ptr);

	XMC_CAN_NODE_FrameCounterConfigure(MULTICAN_CONFIG_0.node0->node_ptr, MULTICAN_CONFIG_0.node0->node_fc_ptr);
	
	XMC_CAN_NODE_EnableLoopBack(MULTICAN_CONFIG_0.node0->node_ptr);

    /* Configure the node event pointer for the alert event with the service request number */
 
    XMC_CAN_NODE_SetEventNodePointer(MULTICAN_CONFIG_0.node0->node_ptr, XMC_CAN_NODE_POINTER_EVENT_ALERT,
	                                 (uint32_t)MULTICAN_CONFIG_0.node0->alert_event_sr); 

    XMC_CAN_NODE_SetEventNodePointer(MULTICAN_CONFIG_0.node0->node_ptr, XMC_CAN_NODE_POINTER_EVENT_LEC,
									 (uint32_t)MULTICAN_CONFIG_0.node0->lec_event_sr);

	XMC_CAN_NODE_SetEventNodePointer(MULTICAN_CONFIG_0.node0->node_ptr, XMC_CAN_NODE_POINTER_EVENT_TRANSFER_OK,
									 (uint32_t)MULTICAN_CONFIG_0.node0->txok_event_sr);

	XMC_CAN_NODE_SetEventNodePointer(MULTICAN_CONFIG_0.node0->node_ptr, XMC_CAN_NODE_POINTER_EVENT_FRAME_COUNTER,
									 (uint32_t)MULTICAN_CONFIG_0.node0->framecount_event_sr);

    /* Enable node events */

	/* reset CCE and INIT bit NCR for node configuration */
	XMC_CAN_NODE_DisableConfigurationChange(MULTICAN_CONFIG_0.node0->node_ptr);

	XMC_CAN_NODE_ResetInitBit(MULTICAN_CONFIG_0.node0->node_ptr);
    /*------------------------------------------------------------------------------------------------------------*/
    /**** NODE1 CONFIGURATION  ****
	---------------------------------------------------------------------------------------------------------------------*/
   
	/* Initialize the GUI configured values for baud rate to NBTR Reg */
	XMC_CAN_NODE_NominalBitTimeConfigure(MULTICAN_CONFIG_0.node1->node_ptr, MULTICAN_CONFIG_0.node1->baudrate_config);

	/* set CCE and INIT bit NCR for node configuration */
	XMC_CAN_NODE_EnableConfigurationChange(MULTICAN_CONFIG_0.node1->node_ptr);

	XMC_CAN_NODE_SetInitBit(MULTICAN_CONFIG_0.node1->node_ptr);

	XMC_CAN_NODE_FrameCounterConfigure(MULTICAN_CONFIG_0.node1->node_ptr, MULTICAN_CONFIG_0.node1->node_fc_ptr);
	
	XMC_CAN_NODE_EnableLoopBack(MULTICAN_CONFIG_0.node1->node_ptr);

    /* Configure the node event pointer for the alert event with the service request number */
 
    XMC_CAN_NODE_SetEventNodePointer(MULTICAN_CONFIG_0.node1->node_ptr, XMC_CAN_NODE_POINTER_EVENT_ALERT,
	                                 (uint32_t)MULTICAN_CONFIG_0.node1->alert_event_sr); 

    XMC_CAN_NODE_SetEventNodePointer(MULTICAN_CONFIG_0.node1->node_ptr, XMC_CAN_NODE_POINTER_EVENT_LEC,
									 (uint32_t)MULTICAN_CONFIG_0.node1->lec_event_sr);

	XMC_CAN_NODE_SetEventNodePointer(MULTICAN_CONFIG_0.node1->node_ptr, XMC_CAN_NODE_POINTER_EVENT_TRANSFER_OK,
									 (uint32_t)MULTICAN_CONFIG_0.node1->txok_event_sr);

	XMC_CAN_NODE_SetEventNodePointer(MULTICAN_CONFIG_0.node1->node_ptr, XMC_CAN_NODE_POINTER_EVENT_FRAME_COUNTER,
									 (uint32_t)MULTICAN_CONFIG_0.node1->framecount_event_sr);

    /* Enable node events */

	/* reset CCE and INIT bit NCR for node configuration */
	XMC_CAN_NODE_DisableConfigurationChange(MULTICAN_CONFIG_0.node1->node_ptr);

	XMC_CAN_NODE_ResetInitBit(MULTICAN_CONFIG_0.node1->node_ptr);
    /*------------------------------------------------------------------------------------------------------------*/
    /**** NODE2 CONFIGURATION  ****
	---------------------------------------------------------------------------------------------------------------------*/
   
	/* Initialize the GUI configured values for baud rate to NBTR Reg */
	XMC_CAN_NODE_NominalBitTimeConfigure(MULTICAN_CONFIG_0.node2->node_ptr, MULTICAN_CONFIG_0.node2->baudrate_config);

	/* set CCE and INIT bit NCR for node configuration */
	XMC_CAN_NODE_EnableConfigurationChange(MULTICAN_CONFIG_0.node2->node_ptr);

	XMC_CAN_NODE_SetInitBit(MULTICAN_CONFIG_0.node2->node_ptr);

	XMC_CAN_NODE_FrameCounterConfigure(MULTICAN_CONFIG_0.node2->node_ptr, MULTICAN_CONFIG_0.node2->node_fc_ptr);
	
	XMC_CAN_NODE_EnableLoopBack(MULTICAN_CONFIG_0.node2->node_ptr);

    /* Configure the node event pointer for the alert event with the service request number */
 
    XMC_CAN_NODE_SetEventNodePointer(MULTICAN_CONFIG_0.node2->node_ptr, XMC_CAN_NODE_POINTER_EVENT_ALERT,
	                                 (uint32_t)MULTICAN_CONFIG_0.node2->alert_event_sr); 

    XMC_CAN_NODE_SetEventNodePointer(MULTICAN_CONFIG_0.node2->node_ptr, XMC_CAN_NODE_POINTER_EVENT_LEC,
									 (uint32_t)MULTICAN_CONFIG_0.node2->lec_event_sr);

	XMC_CAN_NODE_SetEventNodePointer(MULTICAN_CONFIG_0.node2->node_ptr, XMC_CAN_NODE_POINTER_EVENT_TRANSFER_OK,
									 (uint32_t)MULTICAN_CONFIG_0.node2->txok_event_sr);

	XMC_CAN_NODE_SetEventNodePointer(MULTICAN_CONFIG_0.node2->node_ptr, XMC_CAN_NODE_POINTER_EVENT_FRAME_COUNTER,
									 (uint32_t)MULTICAN_CONFIG_0.node2->framecount_event_sr);

    /* Enable node events */

	/* reset CCE and INIT bit NCR for node configuration */
	XMC_CAN_NODE_DisableConfigurationChange(MULTICAN_CONFIG_0.node2->node_ptr);

	XMC_CAN_NODE_ResetInitBit(MULTICAN_CONFIG_0.node2->node_ptr);
    /*------------------------------------------------------------------------------------------------------------*/

    XMC_CAN_AllocateMOtoNodeList(MULTICAN_CONFIG_0.global_ptr->canglobal_ptr, MULTICAN_CONFIG_0.node0->node_num,
                                 MULTICAN_CONFIG_0.lmobj_ptr[0]->number);

    XMC_CAN_AllocateMOtoNodeList(MULTICAN_CONFIG_0.global_ptr->canglobal_ptr, MULTICAN_CONFIG_0.node1->node_num,
                                 MULTICAN_CONFIG_0.lmobj_ptr[1]->number);

    XMC_CAN_AllocateMOtoNodeList(MULTICAN_CONFIG_0.global_ptr->canglobal_ptr, MULTICAN_CONFIG_0.node1->node_num,
                                 MULTICAN_CONFIG_0.lmobj_ptr[2]->number);

    XMC_CAN_AllocateMOtoNodeList(MULTICAN_CONFIG_0.global_ptr->canglobal_ptr, MULTICAN_CONFIG_0.node2->node_num,
                                 MULTICAN_CONFIG_0.lmobj_ptr[3]->number);

    XMC_CAN_AllocateMOtoNodeList(MULTICAN_CONFIG_0.global_ptr->canglobal_ptr, MULTICAN_CONFIG_0.node2->node_num,
                                 MULTICAN_CONFIG_0.lmobj_ptr[4]->number);

	for(temp_mo = 0; temp_mo < NUM_MSGOBJECTS; temp_mo++)
	{
      XMC_CAN_MO_Config(MULTICAN_CONFIG_0.lmobj_ptr[temp_mo]->mo_ptr);

      XMC_CAN_MO_SetEventNodePointer(MULTICAN_CONFIG_0.lmobj_ptr[temp_mo]->mo_ptr, XMC_CAN_MO_POINTER_EVENT_RECEIVE,
                                     (uint32_t)MULTICAN_CONFIG_0.lmobj_ptr[temp_mo]->rx_sr);

      XMC_CAN_MO_SetEventNodePointer(MULTICAN_CONFIG_0.lmobj_ptr[temp_mo]->mo_ptr, XMC_CAN_MO_POINTER_EVENT_TRANSMIT,
								     (uint32_t)MULTICAN_CONFIG_0.lmobj_ptr[temp_mo]->tx_sr);
	}

    XMC_CAN_GATEWAY_InitSourceObject(MULTICAN_CONFIG_0.lmobj_ptr[0]->mo_ptr, *MULTICAN_CONFIG_0.lmobj_ptr[0]->gateway);

    XMC_CAN_TXFIFO_ConfigMOBaseObject(MULTICAN_CONFIG_0.lmobj_ptr[1]->mo_ptr, *MULTICAN_CONFIG_0.lmobj_ptr[1]->fifo);

    XMC_CAN_FIFO_SetSELMO(MULTICAN_CONFIG_0.lmobj_ptr[1]->mo_ptr, MULTICAN_CONFIG_0.lmobj_ptr[1]->fifo->fifo_bottom);

    XMC_CAN_GATEWAY_InitDesObject(MULTICAN_CONFIG_0.lmobj_ptr[1]->mo_ptr);

    XMC_CAN_TXFIFO_ConfigMOSlaveObject(MULTICAN_CONFIG_0.lmobj_ptr[2]->mo_ptr, *MULTICAN_CONFIG_0.lmobj_ptr[2]->fifo);
    XMC_CAN_GATEWAY_InitDesObject(MULTICAN_CONFIG_0.lmobj_ptr[2]->mo_ptr);

    XMC_CAN_MO_EnableEvent(MULTICAN_CONFIG_0.lmobj_ptr[4]->mo_ptr, (uint32_t)XMC_CAN_MO_EVENT_RECEIVE);

  }
  else
  {
    status = MULTICAN_CONFIG_STATUS_FAILURE;
  }
  return (status);
}

